def _run_compare(self):
    def convert(val):
        if val is None: return 0
        try: return float(val)
        except (ValueError, TypeError): return str(val)

    a = convert(self.get_parameter('a'))
    b = convert(self.get_parameter('b'))
    op = self.get_parameter('operation', '==')

    try:
        if op == '==': res = a == b
        elif op == '!=': res = a != b
        elif op == '>': res = a > b
        elif op == '<': res = a < b
        elif op == '>=': res = a >= b
        elif op == '<=': res = a <= b
        else: res = False
        return res
    except: return False

async def execute(self, inputs):
    res = self._run_compare()
    return {'result': res}

def on_parameter_changed(self, name, value):
    if name in ['a', 'b', 'operation']:
        res = self._run_compare()
        self.set_output('result', res)
